#include <iostream>
#include <string>
#include <sstream>
#include <vector>

// Function to simulate running the student's code
std::string run_student_code(const std::string& input_str) {
    std::stringstream ss_in(input_str);
    std::stringstream ss_out;

    // Redirect cin and cout
    std::streambuf* old_cin = std::cin.rdbuf();
    std::streambuf* old_cout = std::cout.rdbuf();
    std::cin.rdbuf(ss_in.rdbuf());
    std::cout.rdbuf(ss_out.rdbuf());

    main(); // Call the student's main function

    // Restore cin and cout
    std::cin.rdbuf(old_cin);
    std::cout.rdbuf(old_cout);

    std::string output = ss_out.str();
    // Filter out input prompts for comparison, keep only the final two lines
    std::string filtered_output;
    std::stringstream temp_ss(output);
    std::string line;
    std::vector<std::string> lines;
    while (std::getline(temp_ss, line)) {
        lines.push_back(line);
    }
    if (lines.size() >= 2) {
        filtered_output += lines[lines.size() - 2] + "\n";
        filtered_output += lines[lines.size() - 1] + "\n";
    }
    return filtered_output;
}

